  ('jenilson-leite', 2024, 307380.55, '[{"tipo":"Outras aplicações e Investimentos","descricao":"CAPITAL SOCIAL SICOOB","valor":11873.11},{"tipo":"Quotas ou quinhões de capital","descricao":"PARTICIPAÇÃO SOCIETÁRIA EMPRESA G O HAGE   CIA","valor":100000},{"tipo":"Outras aplicações e Investimentos","descricao":"BANCO SICOOB","valor":90.17},{"tipo":"Fundos: Ações, Mútuos de Privatização, Invest. Empresas Emergentes, Invest.Participação e Invest. Índice Mercado","descricao":"FUNDO DE INVESTIMENTO","valor":17.07},{"tipo":"Outras aplicações e Investimentos","descricao":"SALDO CAIXA ECONOMICA","valor":400.2},{"tipo":"Veículo automotor terrestre: caminhão, automóvel, moto, etc.","descricao":"CAMINHONETE FORD RANGER ANO 2020/2020 COR CINZA DIESEL","valor":195000}]'::jsonb),
