) AS v(slug, ano_eleicao, total_arrecadado, total_fundo_partidario, total_fundo_eleitoral, total_pessoa_fisica, total_recursos_proprios, maiores_doadores) ON c.slug = v.slug
ON CONFLICT (candidato_id, ano_eleicao) DO UPDATE SET
