  total_fundo_partidario = EXCLUDED.total_fundo_partidario,
  total_fundo_eleitoral = EXCLUDED.total_fundo_eleitoral,
  total_pessoa_fisica = EXCLUDED.total_pessoa_fisica,
  total_recursos_proprios = EXCLUDED.total_recursos_proprios,
  maiores_doadores = EXCLUDED.maiores_doadores,
  fonte = EXCLUDED.fonte;

DO $$
DECLARE missing_patrimonio integer; missing_financiamento integer;
BEGIN
  SELECT count(*) INTO missing_patrimonio
  FROM (VALUES ('jenilson-leite', 2014), ('jenilson-leite', 2018), ('jenilson-leite', 2022), ('jenilson-leite', 2024), ('wanderlei-barbosa', 2010), ('wanderlei-barbosa', 2018), ('wanderlei-barbosa', 2022)) AS expected(slug, ano)
  LEFT JOIN public.candidatos c ON c.slug = expected.slug
  LEFT JOIN public.patrimonio p ON p.candidato_id = c.id AND p.ano_eleicao = expected.ano
  WHERE p.id IS NULL;

  SELECT count(*) INTO missing_financiamento
  FROM (VALUES ('jenilson-leite', 2014), ('jenilson-leite', 2018), ('jenilson-leite', 2022), ('jenilson-leite', 2024), ('wanderlei-barbosa', 2010), ('wanderlei-barbosa', 2022)) AS expected(slug, ano)
  LEFT JOIN public.candidatos c ON c.slug = expected.slug
  LEFT JOIN public.financiamento f ON f.candidato_id = c.id AND f.ano_eleicao = expected.ano
  WHERE f.id IS NULL;

  IF missing_patrimonio <> 0 OR missing_financiamento <> 0 THEN
    RAISE EXCEPTION 'TSE money reconciliation incomplete: patrimonio %, financiamento %', missing_patrimonio, missing_financiamento;
  END IF;
END $$;
